const navItems = [
  { path: '/', label: 'Home', icon: ShieldCheck },
  { path: '/upload', label: 'Verify', icon: Upload },
  { path: '/history', label: 'History', icon: History },
  { path: '/about', label: 'About', icon: Info },
];

export default function Layout() {
  const { user, isLoading, loginWithRedirect, logout } = useAuth();
  const location = useLocation();
  const [mobileOpen, setMobileOpen] = useState(false);

  return (
    <div className="min-h-screen flex flex-col relative">
      {/* Full-page Gen Z background */}
      <img src="https://images.fillout.com/orgid-743119/flowpublicid-hkttzz3oro/widgetid-default/mjqHXhtGehHB7MBXHniPoC/pasted-image-1782803928793-9847uda6.png" alt="" className="fixed inset-0 w-full h-full object-cover -z-10" />
      <div className="fixed inset-0 bg-black/70 -z-10" />
      <header className="sticky top-0 z-50 border-b bg-card/80 backdrop-blur-md">
        <div className="container mx-auto px-4 h-16 flex items-center justify-between">
          <Link to="/" className="flex items-center gap-2 font-bold text-lg">
            <ShieldCheck className="h-6 w-6 text-primary" />
