          </Link>

          <nav className="hidden md:flex items-center gap-1">
            {navItems.map(item => (
              <Link key={item.path} to={item.path}>
                <Button variant={location.pathname === item.path ? 'secondary' : 'ghost'} size="sm">
                  {item.label}
                </Button>
              </Link>
            ))}
