                  </DropdownMenuItem>
                </DropdownMenuContent>
              </DropdownMenu>
            ) : (
              <div className="flex gap-2">
                <Button variant="ghost" size="sm" onClick={() => loginWithRedirect()}>Sign in</Button>
                <Button size="sm" onClick={() => loginWithRedirect({ initialView: 'signup' })}>Get Started</Button>
