import { z } from 'zod';
import { createEndpoint, Certificates } from 'zite-integrations-backend-sdk';

export default createEndpoint({
  authenticated: true,
  description: 'Get certificate scan history for current user',
  inputSchema: z.object({
    offset: z.number().optional(),
    limit: z.number().optional(),
  }),
  outputSchema: z.object({
    records: z.array(z.object({
      id: z.string(),
      fileName: z.string().optional(),
      fileType: z.string().optional(),
      status: z.string().optional(),
      result: z.string().optional(),
      confidenceScore: z.number().optional(),
      originalProbability: z.number().optional(),
      fakeProbability: z.number().optional(),
      reasons: z.string().optional(),
      analysisDetails: z.string().optional(),
      suspiciousRegions: z.string().optional(),
      extractedName: z.string().optional(),
      extractedInstitution: z.string().optional(),
      extractedDate: z.string().optional(),
      extractedCertificateId: z.string().optional(),
      isDuplicate: z.boolean().optional(),
      reportUrl: z.string().optional(),
      submittedAt: z.string().optional(),
      fileUrl: z.string().optional(),
    })),
    hasMore: z.boolean(),
  }),
  execute: async ({ input, context }) => {
    const { records, hasMore } = await Certificates.findAll({
      filters: { uploadedBy: context.user.id },
      offset: input.offset || 0,
      limit: input.limit || 20,
    });

    return {
      records: records.map(r => ({
        id: r.id,
        fileName: r.fileName,
        fileType: r.fileType,
        status: r.status,
        result: r.result,
        confidenceScore: r.confidenceScore,
        originalProbability: r.originalProbability,
        fakeProbability: r.fakeProbability,
        reasons: r.reasons,
        analysisDetails: r.analysisDetails,
        suspiciousRegions: r.suspiciousRegions,
        extractedName: r.extractedName,
        extractedInstitution: r.extractedInstitution,
        extractedDate: r.extractedDate,
        extractedCertificateId: r.extractedCertificateId,
        isDuplicate: r.isDuplicate,
        reportUrl: r.reportUrl,
        submittedAt: r.submittedAt,
        fileUrl: r.file?.[0]?.url,
      })),
      hasMore,
    };
  },
});

