import { z } from 'zod';
import { createEndpoint, Certificates, Users, ZiteError } from 'zite-integrations-backend-sdk';

export default createEndpoint({
  authenticated: true,
  description: 'Get analytics for admin dashboard',
  inputSchema: z.object({}),
  outputSchema: z.object({
    totalScans: z.number(),
    originalCount: z.number(),
    fakeCount: z.number(),
    suspiciousCount: z.number(),
    totalUsers: z.number(),
    recentScans: z.array(z.object({
      id: z.string(),
      fileName: z.string().optional(),
      result: z.string().optional(),
      confidenceScore: z.number().optional(),
      submittedAt: z.string().optional(),
    })),
  }),
  execute: async ({ context }) => {
    if (context.user.role !== 'Admin') {
      throw new ZiteError({ code: 'FORBIDDEN', message: 'Admin access required' });
    }

    const [allCerts, usersResult] = await Promise.all([
      Certificates.findAll({ limit: 2000 }),
      Users.findAll({ limit: 2000 }),
    ]);

    const certs = allCerts.records;
    const originalCount = certs.filter(c => c.result === 'Original').length;
    const fakeCount = certs.filter(c => c.result === 'Fake').length;
    const suspiciousCount = 0;

    const recentScans = certs
      .sort((a, b) => (b.submittedAt || '').localeCompare(a.submittedAt || ''))
      .slice(0, 10)
      .map(r => ({
        id: r.id,
        fileName: r.fileName,
        result: r.result,
        confidenceScore: r.confidenceScore,
        submittedAt: r.submittedAt,
      }));

    return {
      totalScans: certs.length,
      originalCount,
      fakeCount,
      suspiciousCount,
      totalUsers: usersResult.records.length,
      recentScans,
    };
  },
});

import { z } from 'zod';
import { createEndpoint, AuditLogs, ZiteError } from 'zite-integrations-backend-sdk';

export default createEndpoint({
  authenticated: true,
  description: 'Admin: get audit logs',
  inputSchema: z.object({}),
  outputSchema: z.object({
    logs: z.array(z.object({
      id: z.string(),
      action: z.string().optional(),
      details: z.string().optional(),
      timestamp: z.string().optional(),
    })),
  }),
  execute: async ({ context }) => {
    if (context.user.role !== 'Admin') {
      throw new ZiteError({ code: 'FORBIDDEN', message: 'Admin access required' });
    }
    const { records } = await AuditLogs.findAll({ limit: 100 });
    return {
      logs: records.map(l => ({
        id: l.id,
        action: l.action,
        details: l.details,
        timestamp: l.timestamp,
      })),
    };
  },
});

import { useState, useEffect } from 'react';
