export default function AdminPage() {
  const { user, isLoading, loginWithRedirect } = useAuth();
  const [analytics, setAnalytics] = useState<GetAnalyticsOutputType | null>(null);
  const [users, setUsers] = useState<AdminGetUsersOutputType['users']>([]);
  const [logs, setLogs] = useState<GetAuditLogsOutputType['logs']>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (!isLoading && !user) loginWithRedirect({ redirectUrl: window.location.href });
  }, [isLoading, user, loginWithRedirect]);

  useEffect(() => {
    if (!user || user.role !== 'Admin') return;
    Promise.all([
      getAnalytics({}),
      adminGetUsers({}),
      getAuditLogs({}),
    ]).then(([a, u, l]) => {
      setAnalytics(a);
      setUsers(u.users);
      setLogs(l.logs);
      setLoading(false);
    }).catch(() => setLoading(false));
  }, [user]);

  if (isLoading || !user) return null;
  if (user.role !== 'Admin') {
    return (
      <div className="container mx-auto px-4 py-20 text-center">
        <ShieldAlert className="h-16 w-16 mx-auto text-destructive mb-4" />
        <h1 className="text-2xl font-bold mb-2">Access Denied</h1>
        <p className="text-muted-foreground">You need admin privileges to access this page.</p>
      </div>
    );
  }

  if (loading) {
    return (
      <div className="container mx-auto px-4 py-10 space-y-4">
        {Array.from({ length: 4 }).map((_, i) => <Skeleton key={i} className="h-32 rounded-xl" />)}
      </div>
    );
  }

  const pieData = [
    { name: 'Original', value: analytics?.originalCount || 0, color: 'hsl(152, 60%, 36%)' },
    { name: 'Fake', value: analytics?.fakeCount || 0, color: 'hsl(0, 72%, 51%)' },

  ].filter(d => d.value > 0);

  const handleRoleChange = async (userId: string, role: string) => {
    try {
      await adminUpdateRole({ userId, role });
      setUsers(prev => prev.map(u => u.id === userId ? { ...u, role } : u));
      toast.success('Role updated');
    } catch { toast.error('Failed to update role'); }
  };

  return (
    <div className="container mx-auto px-4 py-10">
      <h1 className="text-3xl font-bold mb-8">Admin Dashboard</h1>

      {/* Stats */}
      <div className="grid sm:grid-cols-2 lg:grid-cols-4 gap-4 mb-8">
        {[
          { label: 'Total Scans', value: analytics?.totalScans, icon: FileSearch, color: 'text-primary' },
          { label: 'Original', value: analytics?.originalCount, icon: ShieldCheck, color: 'text-primary' },
          { label: 'Fake', value: analytics?.fakeCount, icon: ShieldAlert, color: 'text-destructive' },
          { label: 'Users', value: analytics?.totalUsers, icon: Users, color: 'text-chart-2' },
        ].map((s, i) => (
