                          {s.result}
                        </Badge>
                        <span className="truncate flex-1">{s.fileName}</span>
                        <span className="text-muted-foreground text-xs">{s.confidenceScore}%</span>
                      </div>
                    ))}
                  </div>
                ) : <p className="text-center text-muted-foreground pt-10">No scans yet</p>}
              </CardContent>
            </Card>
          </div>
        </TabsContent>

        <TabsContent value="users" className="mt-6">
          <Card>
            <CardContent className="pt-6">
              <div className="space-y-3">
                {users.map(u => (
                  <div key={u.id} className="flex items-center gap-4 py-3 border-b last:border-0">
                    <div className="h-9 w-9 rounded-full bg-primary/10 flex items-center justify-center text-sm font-semibold text-primary">
                      {(u.name?.[0] || u.email?.[0] || '?').toUpperCase()}
                    </div>
                    <div className="flex-1 min-w-0">
                      <p className="font-medium text-sm truncate">{u.name || u.email}</p>
                      <p className="text-xs text-muted-foreground">{u.email} · {u.totalScans ?? 0} scans</p>
                    </div>
                    <Select value={u.role || 'User'} onValueChange={v => handleRoleChange(u.id, v)}>
                      <SelectTrigger className="w-28 h-8 text-xs"><SelectValue /></SelectTrigger>
                      <SelectContent>
                        <SelectItem value="User">User</SelectItem>
                        <SelectItem value="Admin">Admin</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                ))}
              </div>
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="logs" className="mt-6">
          <Card>
            <CardContent className="pt-6">
              {logs.length === 0 ? (
                <p className="text-center text-muted-foreground py-8">No audit logs yet.</p>
              ) : (
                <div className="space-y-2 max-h-96 overflow-y-auto">
                  {logs.map(l => (
                    <div key={l.id} className="flex items-start gap-3 py-2 border-b last:border-0 text-sm">
                      <Activity className="h-4 w-4 text-muted-foreground mt-0.5 shrink-0" />
                      <div className="min-w-0">
                        <p className="font-medium">{l.action}</p>
                        <p className="text-muted-foreground text-xs truncate">{l.details}</p>
                        <p className="text-muted-foreground text-xs">{l.timestamp ? format(new Date(l.timestamp), 'MMM d, yyyy h:mm a') : ''}</p>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>
    </div>
  );
}

import { z } from 'zod';
import { createEndpoint, Users, ZiteError } from 'zite-integrations-backend-sdk';

export default createEndpoint({
  authenticated: true,
  description: 'Admin: list all users',
  inputSchema: z.object({}),
  outputSchema: z.object({
    users: z.array(z.object({
      id: z.string(),
      name: z.string().optional(),
      email: z.string().optional(),
      role: z.string().optional(),
      totalScans: z.number().optional(),
      joinedAt: z.string().optional(),
    })),
  }),
  execute: async ({ context }) => {
    if (context.user.role !== 'Admin') {
      throw new ZiteError({ code: 'FORBIDDEN', message: 'Admin access required' });
    }
    const { records } = await Users.findAll({ limit: 200 });
    return {
      users: records.map(u => ({
        id: u.id,
        name: u.name,
        email: u.email,
        role: u.role,
        totalScans: u.totalScans,
        joinedAt: u.joinedAt,
      })),
    };
  },
});

import { useState, useCallback, useEffect, useRef } from 'react';
import { useAuth } from 'zite-auth-sdk';
import { uploadFile } from 'zite-file-upload-sdk';
import { analyzeCertificate, AnalyzeCertificateOutputType } from 'zite-endpoints-sdk';
import { Button } from '@/components/ui/button';
import { Card, CardContent } from '@/components/ui/card';
import { Progress } from '@/components/ui/progress';
import { Upload, FileImage, FileText, X, ShieldCheck, Loader2 } from 'lucide-react';
import { toast } from 'sonner';
import ResultCard from '@/components/ResultCard';

const ALLOWED_TYPES = ['image/jpeg', 'image/png', 'application/pdf'];
const MAX_SIZE = 10 * 1024 * 1024; // 10MB

export default function UploadPage() {
  const { user, isLoading, loginWithRedirect } = useAuth();
  const [file, setFile] = useState<File | null>(null);
  const [preview, setPreview] = useState<string | null>(null);
  const [analyzing, setAnalyzing] = useState(false);
  const [result, setResult] = useState<AnalyzeCertificateOutputType | null>(null);
  const [dragActive, setDragActive] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (!isLoading && !user) loginWithRedirect({ redirectUrl: window.location.href });
  }, [isLoading, user, loginWithRedirect]);

  const handleFile = useCallback((f: File) => {
    if (!ALLOWED_TYPES.includes(f.type)) {
      toast.error('Please upload a JPG, PNG, or PDF file');
      return;
    }
    if (f.size > MAX_SIZE) {
      toast.error('File size must be under 10MB');
      return;
    }
    setFile(f);
    setResult(null);
    if (f.type.startsWith('image/')) {
      const reader = new FileReader();
      reader.onload = e => setPreview(e.target?.result as string);
      reader.readAsDataURL(f);
    } else {
      setPreview(null);
    }
  }, []);

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setDragActive(false);
    const f = e.dataTransfer.files[0];
    if (f) handleFile(f);
  }, [handleFile]);

  const handleAnalyze = async () => {
    if (!file) return;
    setAnalyzing(true);
    try {
      const ext = file.name.split('.').pop()?.toLowerCase() || 'jpg';
      const { fileUrl } = await uploadFile({ data: file, filename: file.name });
      const res = await analyzeCertificate({ fileUrl, fileName: file.name, fileType: ext });
      setResult(res);
      toast.success('Analysis complete!');
    } catch (err: any) {
      toast.error(err?.message || 'Analysis failed');
    } finally {
      setAnalyzing(false);
    }
  };

  if (isLoading || !user) return null;

  return (
    <div className="container mx-auto px-4 py-10 max-w-3xl">
      <div className="text-center mb-8">
        <h1 className="text-3xl font-bold mb-2">Verify Certificate</h1>
        <p className="text-muted-foreground">Upload a certificate to check its authenticity</p>
      </div>

      {!result ? (
        <Card>
          <CardContent className="pt-6 space-y-6">
            {/* Drop zone */}
            <div
              className={`relative border-2 border-dashed rounded-xl p-10 text-center transition-colors cursor-pointer
                ${dragActive ? 'border-primary bg-accent' : 'border-border hover:border-primary/50'}`}
              onDragOver={e => { e.preventDefault(); setDragActive(true); }}
              onDragLeave={() => setDragActive(false)}
              onDrop={handleDrop}
              onClick={() => inputRef.current?.click()}
            >
              <input
                ref={inputRef}
                type="file"
                accept=".jpg,.jpeg,.png,.pdf"
                className="hidden"
                onChange={e => { const f = e.target.files?.[0]; if (f) handleFile(f); }}
              />
              {file ? (
                <div className="space-y-3">
                  {preview ? (
                    <img src={preview} alt="Preview" className="max-h-60 mx-auto rounded-lg shadow-sm" />
                  ) : file.type === 'application/pdf' ? (
                    <FileText className="h-16 w-16 mx-auto text-primary" />
                  ) : (
                    <FileImage className="h-16 w-16 mx-auto text-primary" />
                  )}
                  <div className="flex items-center justify-center gap-2">
                    <span className="text-sm font-medium">{file.name}</span>
                    <span className="text-xs text-muted-foreground">({(file.size / 1024).toFixed(0)} KB)</span>
                    <Button
                      variant="ghost"
                      size="icon"
                      className="h-6 w-6"
                      onClick={e => { e.stopPropagation(); setFile(null); setPreview(null); setResult(null); }}
                    >
                      <X className="h-4 w-4" />
                    </Button>
                  </div>
                </div>
              ) : (
                <div className="space-y-3">
                  <Upload className="h-12 w-12 mx-auto text-muted-foreground" />
                  <div>
                    <p className="font-medium">Drag & drop your certificate here</p>
                    <p className="text-sm text-muted-foreground mt-1">or click to browse — JPG, PNG, PDF up to 10MB</p>
                  </div>
                </div>
              )}
            </div>

            <Button onClick={handleAnalyze} disabled={!file || analyzing} className="w-full gap-2" size="lg">
              {analyzing ? <Loader2 className="h-5 w-5 animate-spin" /> : <ShieldCheck className="h-5 w-5" />}
              {analyzing ? 'Analyzing…' : 'Analyze Certificate'}
            </Button>

            {analyzing && (
              <div className="space-y-2">
                <p className="text-sm text-center text-muted-foreground">AI is examining your certificate…</p>
                <Progress value={undefined} className="h-2 animate-pulse" />
              </div>
            )}
          </CardContent>
        </Card>
      ) : (
        <div className="space-y-4">
          <ResultCard result={result} preview={preview} fileName={file?.name} />
          <Button
            variant="outline"
            className="w-full"
            onClick={() => { setFile(null); setPreview(null); setResult(null); }}
          >
            Verify Another Certificate
          </Button>
        </div>
      )}
    </div>
  );
}

import { z } from 'zod';
import { createEndpoint, Certificates, ZitePdf, ZiteError } from 'zite-integrations-backend-sdk';

export default createEndpoint({
  authenticated: true,
  description: 'Generate a PDF verification report for a certificate',
  inputSchema: z.object({ certificateId: z.string() }),
  outputSchema: z.object({ url: z.string() }),
  execute: async ({ input, context }) => {
    const cert = await Certificates.findOne({ id: input.certificateId });
    if (!cert) throw new ZiteError({ code: 'NOT_FOUND', message: 'Certificate not found' });

    const e = (s: unknown) => String(s ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
    const safeNum = (n: unknown) => { const v = Number(n); return Number.isFinite(v) ? v : 0; };

    const isOriginal = cert.result === 'Original';
    const isFake = cert.result === 'Fake';
    const statusColor = isOriginal ? '#059669' : '#dc2626';
    const statusBg = isOriginal ? '#ecfdf5' : '#fef2f2';

    let suspiciousHtml = '';
    try {
      const regions = JSON.parse(cert.suspiciousRegions || '[]');
      if (Array.isArray(regions) && regions.length > 0) {
        suspiciousHtml = regions.map((r: string) => `<li>${e(r)}</li>`).join('');
      }
    } catch {
      if (cert.suspiciousRegions) {
        suspiciousHtml = `<li>${e(cert.suspiciousRegions)}</li>`;
      }
    }

    const reasonsHtml = (cert.reasons || '').split('\n').filter(Boolean).map(r => `<li>${e(r.replace(/^[•\-\*]\s*/, ''))}</li>`).join('');

    const origProb = safeNum(cert.originalProbability);
    const fakeProb = safeNum(cert.fakeProbability);

    const html = `<!doctype html>
<html>
<head>
<meta charset="utf-8" />
<style>
  @page { size: a4; margin: 0.6in; }
  body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; color: #1e293b; font-size: 10pt; line-height: 1.5; position: relative; }
  .watermark { position: fixed; top: 50%; left: 50%; transform: translate(-50%, -50%); opacity: 0.24; pointer-events: none; z-index: -1; width: 420px; height: auto; }
  .header { display: flex; justify-content: space-between; align-items: center; border-bottom: 2px solid #0d9488; padding-bottom: 12px; margin-bottom: 20px; }
  .logo { font-size: 18pt; font-weight: 700; color: #0d9488; }
  .subtitle { font-size: 9pt; color: #64748b; }
  .status-badge { display: inline-block; padding: 8px 24px; border-radius: 8px; font-size: 14pt; font-weight: 700; color: ${statusColor}; background: ${statusBg}; border: 2px solid ${statusColor}; }
  .section { margin: 18px 0 8px; font-size: 11pt; font-weight: 700; color: #0d9488; border-bottom: 1px solid #e2e8f0; padding-bottom: 4px; }
  .grid { display: grid; grid-template-columns: 1fr 1fr; gap: 8px 24px; }
  .label { font-size: 8pt; color: #94a3b8; text-transform: uppercase; letter-spacing: 0.5px; }
  .value { font-size: 10pt; font-weight: 500; }
  .prob-bar { height: 18px; border-radius: 9px; background: #f1f5f9; overflow: hidden; margin: 4px 0; }
  .prob-fill-green { height: 100%; background: #059669; border-radius: 9px; }
  .prob-fill-red { height: 100%; background: #dc2626; border-radius: 9px; }
  ul { padding-left: 18px; margin: 4px 0; }
  li { margin: 3px 0; font-size: 9.5pt; }
  .detail-text { font-size: 9.5pt; color: #475569; background: #f8fafc; padding: 10px; border-radius: 6px; }
  .footer { margin-top: 30px; padding-top: 10px; border-top: 1px solid #e2e8f0; font-size: 8pt; color: #94a3b8; text-align: center; }
  .warning { font-size: 8pt; color: #d97706; background: #fffbeb; padding: 6px 10px; border-radius: 4px; margin-top: 16px; }
</style>
</head>
<body>
  <img class="watermark" src="https://images.fillout.com/orgid-743119/flowpublicid-hkttzz3oro/widgetid-default/gWX4kvXqRgktnUozPGcyUT/pasted-image-1782972749519-1r1wokqx.png" />
  <div class="header">
    <div><div class="logo">🛡️ CertiVerify</div><div class="subtitle">Certificate Authenticity Verification Report</div></div>
    <div style="text-align:right"><div class="subtitle">Report ID: ${e(cert.id.slice(0, 8))}</div><div class="subtitle">${new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' })}</div></div>
  </div>

  <div style="text-align:center; margin: 20px 0;">
    <div class="status-badge">${e(cert.result)} Certificate</div>
    <div style="font-size:28pt; font-weight:800; color:${statusColor}; margin-top:8px;">${safeNum(cert.confidenceScore).toFixed(1)}%</div>
    <div class="subtitle">Confidence Score</div>
  </div>

  <div class="section">Fraud Probability Assessment</div>
  <div class="grid">
    <div>
      <div class="label">Original Probability</div>
      <div class="prob-bar"><div class="prob-fill-green" style="width:${origProb}%"></div></div>
      <div class="value" style="color:#059669">${origProb.toFixed(1)}%</div>
    </div>
    <div>
      <div class="label">Fake Probability</div>
      <div class="prob-bar"><div class="prob-fill-red" style="width:${fakeProb}%"></div></div>
      <div class="value" style="color:#dc2626">${fakeProb.toFixed(1)}%</div>
    </div>
  </div>

  <div class="section">Certificate Details (OCR Extracted)</div>
  <div class="grid">
    <div><div class="label">File Name</div><div class="value">${e(cert.fileName)}</div></div>
    <div><div class="label">Certificate ID</div><div class="value">${e(cert.extractedCertificateId) || 'Not found'}</div></div>
    <div><div class="label">Holder Name</div><div class="value">${e(cert.extractedName) || 'Not found'}</div></div>
    <div><div class="label">Institution</div><div class="value">${e(cert.extractedInstitution) || 'Not found'}</div></div>
    <div><div class="label">Date Issued</div><div class="value">${e(cert.extractedDate) || 'Not found'}</div></div>
    <div><div class="label">Verified By</div><div class="value">${e(context.user.email)}</div></div>
  </div>

  <div class="section">Key Findings</div>
  <ul>${reasonsHtml || '<li>No specific findings</li>'}</ul>

  ${suspiciousHtml ? `<div class="section">⚠️ Suspicious Regions Identified</div><ul>${suspiciousHtml}</ul>` : ''}

  <div class="section">Detailed Analysis</div>
  <div class="detail-text">${e(cert.analysisDetails)}</div>

  <div class="warning">⚠️ This report is generated by AI-based analysis and is advisory only. For legal verification, always confirm with the official issuing institution.</div>

  <div class="footer">Generated by CertiVerify — AI-Powered Certificate Authenticity Checker • ${new Date().toISOString()}</div>
</body>
</html>`;

    const { url } = await ZitePdf.renderHtml({
      html,
      filename: `CertiVerify-Report-${cert.id.slice(0, 8)}.pdf`,
    });

    await Certificates.update({ id: cert.id, record: { reportUrl: url } });

    return { url };
  },
});

