import { useState, useEffect } from 'react';
import { useAuth } from 'zite-auth-sdk';
import { getHistory, GetHistoryOutputType, generateReport } from 'zite-endpoints-sdk';
import { Card, CardContent } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Skeleton } from '@/components/ui/skeleton';
import { Dialog, DialogContent, DialogHeader, DialogTitle } from '@/components/ui/dialog';
import { ShieldCheck, ShieldAlert, ShieldQuestion, Clock, ChevronRight, Download, Loader2, Copy, AlertTriangle, FileText } from 'lucide-react';
import { format } from 'date-fns';
import { toast } from 'sonner';

type CertRecord = GetHistoryOutputType['records'][0];

export default function HistoryPage() {
  const { user, isLoading, loginWithRedirect } = useAuth();
  const [records, setRecords] = useState<CertRecord[]>([]);
  const [loading, setLoading] = useState(true);
  const [selected, setSelected] = useState<CertRecord | null>(null);
  const [downloading, setDownloading] = useState(false);

  useEffect(() => {
    if (!isLoading && !user) loginWithRedirect({ redirectUrl: window.location.href });
  }, [isLoading, user, loginWithRedirect]);

  useEffect(() => {
    if (!user) return;
    getHistory({ offset: 0, limit: 50 }).then(r => { setRecords(r.records); setLoading(false); });
  }, [user]);

  if (isLoading || !user) return null;

  const resultIcon = (r?: string) => {
    if (r === 'Original') return <ShieldCheck className="h-5 w-5 text-primary" />;
    if (r === 'Fake') return <ShieldAlert className="h-5 w-5 text-destructive" />;
    return <ShieldQuestion className="h-5 w-5 text-yellow-500" />;
  };

  const handleDownload = async (certId: string) => {
    setDownloading(true);
    try {
      const { url } = await generateReport({ certificateId: certId });
      window.open(url, '_blank');
      toast.success('Report generated!');
    } catch { toast.error('Failed to generate report'); }
    finally { setDownloading(false); }
  };

  return (
    <div className="container mx-auto px-4 py-10 max-w-3xl">
      <h1 className="text-3xl font-bold mb-2">Scan History</h1>
      <p className="text-muted-foreground mb-8">Your past certificate verifications</p>

      {loading ? (
        <div className="space-y-3">{Array.from({ length: 4 }).map((_, i) => <Skeleton key={i} className="h-20 rounded-xl" />)}</div>
      ) : records.length === 0 ? (
        <Card><CardContent className="py-12 text-center text-muted-foreground">No scans yet. Upload a certificate to get started.</CardContent></Card>
      ) : (
        <div className="space-y-3">
          {records.map(r => (
            <Card key={r.id} className="cursor-pointer hover:shadow-md transition-shadow" onClick={() => setSelected(r)}>
              <CardContent className="py-4 flex items-center gap-4">
                {resultIcon(r.result)}
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2">
                    <p className="font-medium truncate">{r.fileName || 'Untitled'}</p>
                    {r.isDuplicate && <Copy className="h-3.5 w-3.5 text-yellow-500" />}
                  </div>
                  <p className="text-xs text-muted-foreground flex items-center gap-1">
                    <Clock className="h-3 w-3" />
                    {r.submittedAt ? format(new Date(r.submittedAt), 'MMM d, yyyy h:mm a') : '—'}
                    {r.extractedInstitution && <span className="ml-2">· {r.extractedInstitution}</span>}
                  </p>
                </div>
                <div className="flex items-center gap-2 shrink-0">
                  {r.result && (
                    <Badge variant={r.result === 'Original' ? 'default' : r.result === 'Fake' ? 'destructive' : 'secondary'}>
                      {r.result}
                    </Badge>
                  )}
                  {r.confidenceScore != null && <span className="text-sm font-semibold">{r.confidenceScore}%</span>}
                  <ChevronRight className="h-4 w-4 text-muted-foreground" />
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      )}

      <Dialog open={!!selected} onOpenChange={() => setSelected(null)}>
        <DialogContent className="max-w-lg max-h-[85vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>{selected?.fileName}</DialogTitle>
          </DialogHeader>
          {selected && (
            <div className="space-y-4">
              {/* Status + Score */}
              <div className="flex items-center gap-3">
                {resultIcon(selected.result)}
                <Badge variant={selected.result === 'Original' ? 'default' : selected.result === 'Fake' ? 'destructive' : 'secondary'}>
                  {selected.result} Certificate
                </Badge>
                <span className="ml-auto font-bold text-xl">{selected.confidenceScore}%</span>
              </div>

              {/* Fraud Probability */}
              {(selected.originalProbability != null || selected.fakeProbability != null) && (
                <div className="space-y-2">
                  <p className="text-sm font-semibold">Fraud Probability</p>
                  <div className="grid grid-cols-2 gap-3">
                    <div className="text-center bg-primary/10 rounded-lg p-3">
                      <p className="text-2xl font-bold text-primary">{(selected.originalProbability ?? 0).toFixed(1)}%</p>
                      <p className="text-xs text-muted-foreground">Original</p>
                    </div>
                    <div className="text-center bg-destructive/10 rounded-lg p-3">
                      <p className="text-2xl font-bold text-destructive">{(selected.fakeProbability ?? 0).toFixed(1)}%</p>
                      <p className="text-xs text-muted-foreground">Fake</p>
                    </div>
                  </div>
                </div>
              )}

              {selected.isDuplicate && (
                <div className="flex items-center gap-2 bg-yellow-500/10 text-yellow-500 rounded-lg px-3 py-2 text-sm">
                  <Copy className="h-4 w-4" /> Duplicate certificate detected
                </div>
              )}

              {/* OCR Data */}
              {(selected.extractedName || selected.extractedInstitution) && (
                <div>
                  <p className="text-sm font-semibold mb-2 flex items-center gap-2"><FileText className="h-4 w-4 text-primary" /> Extracted Data</p>
                  <div className="grid grid-cols-2 gap-2 bg-muted/50 rounded-lg p-3 text-sm">
                    {selected.extractedName && <div><span className="text-xs text-muted-foreground block">Name</span>{selected.extractedName}</div>}
                    {selected.extractedInstitution && <div><span className="text-xs text-muted-foreground block">Institution</span>{selected.extractedInstitution}</div>}
                    {selected.extractedDate && <div><span className="text-xs text-muted-foreground block">Date</span>{selected.extractedDate}</div>}
                    {selected.extractedCertificateId && <div><span className="text-xs text-muted-foreground block">Cert ID</span>{selected.extractedCertificateId}</div>}
                  </div>
                </div>
              )}

              {selected.fileUrl && selected.fileType !== 'PDF' && (
                <img src={selected.fileUrl} alt="" className="rounded-lg border max-h-48 mx-auto" />
              )}

              {/* Suspicious Regions */}
              {selected.suspiciousRegions && (() => {
                let regions: string[] = [];
                try { const p = JSON.parse(selected.suspiciousRegions); if (Array.isArray(p)) regions = p; } catch { regions = [selected.suspiciousRegions]; }
                return regions.length > 0 ? (
                  <div>
                    <p className="text-sm font-semibold mb-2 flex items-center gap-2"><AlertTriangle className="h-4 w-4 text-destructive" /> Suspicious Regions</p>
                    <div className="space-y-1">
                      {regions.map((r, i) => (
                        <div key={i} className="text-xs bg-destructive/5 border border-destructive/20 rounded px-2 py-1.5 flex items-start gap-1.5">
                          <AlertTriangle className="h-3 w-3 text-destructive shrink-0 mt-0.5" /> {r}
                        </div>
                      ))}
                    </div>
                  </div>
                ) : null;
              })()}

              {selected.reasons && (
                <div>
                  <p className="text-sm font-semibold mb-1">Key Findings</p>
                  <p className="text-sm text-muted-foreground whitespace-pre-line bg-muted/50 rounded-lg p-3">{selected.reasons}</p>
                </div>
              )}
              {selected.analysisDetails && (
                <div>
                  <p className="text-sm font-semibold mb-1">Detailed Analysis</p>
                  <p className="text-sm text-muted-foreground bg-muted/50 rounded-lg p-3">{selected.analysisDetails}</p>
                </div>
              )}

              <Button onClick={() => handleDownload(selected.id)} disabled={downloading} className="w-full gap-2" variant="outline">
                {downloading ? <Loader2 className="h-4 w-4 animate-spin" /> : <Download className="h-4 w-4" />}
                {downloading ? 'Generating…' : 'Download Report (PDF)'}
              </Button>
            </div>
          )}
        </DialogContent>
      </Dialog>
    </div>
  );
}

import { z } from 'zod';
import { createEndpoint, Users, AuditLogs, ZiteError } from 'zite-integrations-backend-sdk';

export default createEndpoint({
  authenticated: true,
  description: 'Admin: update user role',
  inputSchema: z.object({
    userId: z.string(),
    role: z.string(),
  }),
  outputSchema: z.object({ success: z.boolean() }),
  execute: async ({ input, context }) => {
    if (context.user.role !== 'Admin') {
      throw new ZiteError({ code: 'FORBIDDEN', message: 'Admin access required' });
    }
    await Users.update({ id: input.userId, record: { role: input.role as any } });
    await AuditLogs.create({
      record: {
        user: context.user.id,
        action: 'Role Updated',
        details: `Changed user ${input.userId} role to ${input.role}`,
      },
    });
    return { success: true };
  },
});

import { z } from 'zod';
import { createEndpoint, Certificates, AuditLogs, Users } from 'zite-integrations-backend-sdk';
import OpenAI from 'openai';

export default createEndpoint({
  authenticated: true,
  description: 'Analyze an uploaded certificate for authenticity using AI vision',
  inputSchema: z.object({
    fileUrl: z.string(),
    fileName: z.string(),
    fileType: z.string(),
  }),
  outputSchema: z.object({
    certificateId: z.string(),
    result: z.string(),
    confidenceScore: z.number(),
    originalProbability: z.number(),
    fakeProbability: z.number(),
    reasons: z.string(),
    analysisDetails: z.string(),
    suspiciousRegions: z.string(),
    extractedName: z.string(),
    extractedInstitution: z.string(),
    extractedDate: z.string(),
    extractedCertificateId: z.string(),
    extractedText: z.string(),
    isDuplicate: z.boolean(),
    duplicateOf: z.string(),
    qrCodeFound: z.boolean(),
    digitalSignatureFound: z.boolean(),
    tamperingIndicators: z.string(),
  }),
  execute: async ({ input, context }) => {
    // Step 1: Create certificate record
    const cert = await Certificates.create({
      record: {
        fileName: input.fileName,
        file: [{ url: input.fileUrl }],
        fileType: input.fileType.toUpperCase() as any,
        uploadedBy: context.user.id,
        status: 'Analyzing',
      },
    });

    // Step 2: Check for duplicates (same file name + same user)
    const { records: existing } = await Certificates.findAll({
      filters: { fileName: input.fileName, uploadedBy: context.user.id, status: 'Completed' },
      limit: 5,
    });
    const duplicateRecord = existing.find(r => r.id !== cert.id);
    const isDuplicate = !!duplicateRecord;
    const duplicateOf = duplicateRecord?.id || '';

    // Step 3: AI Vision Analysis
    const client = new OpenAI({ apiKey: process.env.ZITE_OPENAI_ACCESS_TOKEN });

    const systemPrompt = `You are an expert certificate forensics analyst. Perform a comprehensive authenticity analysis on the uploaded certificate image. Analyze ALL of the following dimensions:

## 1. QR Code / Barcode Verification
- Is a QR code or barcode present?
- Does it appear genuine and properly embedded (not pasted on)?

## 2. Digital Signature / Seal Detection
- Is an official digital signature, rubber stamp, or embossed seal present?
- Does it match expected patterns for institutional certificates?

## 3. Logo Authenticity
- Is the logo clear, high-resolution, and properly positioned?
- Any signs of low-quality copy-paste or misalignment?

## 4. Signature Verification
- Are handwritten/digital signatures present and natural-looking?
- Any signs of digital stamp or copy-paste artifacts?

## 5. Text & Font Consistency
- Is the font uniform throughout? Any font switching mid-text?
- Text alignment, spacing consistency, spelling/grammar errors?

## 6. Layout & Template Consistency
- Does the certificate follow standard institutional formatting?
- Borders, margins, watermarks, paper texture consistency?

## 7. Image Tampering Detection
- Signs of copy-move forgery, splicing, or content-aware fill?
- Inconsistent lighting, shadows, compression artifacts?
- Altered names, dates, grades, or ID numbers?

## 8. OCR Text Extraction
- Extract: holder name, institution name, date issued, certificate ID/number
- Extract any other visible text

## 9. Fraud Probability Assessment
- Give exact percentage: originalProbability + fakeProbability = 100

## 10. Suspicious Regions
- List specific areas on the certificate that look suspicious (e.g., "Name field shows font inconsistency", "Logo has compression artifacts", "Signature appears digitally stamped")

Respond ONLY in this exact JSON format:
{
  "result": "Original" | "Fake",
  "confidenceScore": <number 0-100>,
  "originalProbability": <number 0-100>,
  "fakeProbability": <number 0-100>,
  "reasons": "<bullet list with • prefix for each key finding>",
  "analysisDetails": "<detailed multi-paragraph analysis covering all 10 dimensions>",
  "suspiciousRegions": "<JSON array of strings describing each suspicious area, e.g. [\\"Logo area: low resolution\\", \\"Name field: font mismatch\\"]>",
  "extractedName": "<holder name or empty>",
  "extractedInstitution": "<institution name or empty>",
  "extractedDate": "<date issued or empty>",
  "extractedCertificateId": "<certificate number/ID or empty>",
  "extractedText": "<all visible text on the certificate>",
  "qrCodeFound": true | false,
  "digitalSignatureFound": true | false,
  "tamperingIndicators": "<bullet list of specific tampering signs found, or 'None detected'>"
}`;

    const isPdf = input.fileType.toLowerCase() === 'pdf';

    // Build the user message content based on file type
    const userContent: any[] = [
      { type: 'text', text: `Perform a full forensic authenticity analysis on this certificate. File: ${input.fileName}` },
    ];

    if (isPdf) {
      // For PDFs: fetch the file, convert to base64, and send as a file input
      const pdfResponse = await fetch(input.fileUrl);
      const pdfBuffer = await pdfResponse.arrayBuffer();
      const bytes = new Uint8Array(pdfBuffer);
      let binary = '';
      const chunkSize = 8192;
      for (let i = 0; i < bytes.length; i += chunkSize) {
        binary += String.fromCharCode(...bytes.subarray(i, i + chunkSize));
      }
      const base64 = btoa(binary);
      userContent.push({
        type: 'file',
        file: {
          file_data: `data:application/pdf;base64,${base64}`,
          filename: input.fileName,
        },
      });
    } else {
      // For images: send as image_url
      userContent.push({ type: 'image_url', image_url: { url: input.fileUrl } });
    }

    const completion = await client.chat.completions.create({
      model: 'gpt-5',
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userContent },
      ],
      response_format: { type: 'json_object' },
    });

    const raw = completion.choices[0].message.content || '{}';
    let analysis: any;
    try {
      analysis = JSON.parse(raw);
    } catch {
      analysis = {
        result: 'Fake', confidenceScore: 50, originalProbability: 50, fakeProbability: 50,
        reasons: 'Could not parse analysis', analysisDetails: raw, suspiciousRegions: '[]',
        extractedName: '', extractedInstitution: '', extractedDate: '', extractedCertificateId: '',
        extractedText: '', qrCodeFound: false, digitalSignatureFound: false, tamperingIndicators: 'Analysis parsing failed',
      };
    }

    const validResult = ['Original', 'Fake'].includes(analysis.result) ? analysis.result : 'Fake';
    const origProb = Number(analysis.originalProbability) || 50;
    const fakeProb = Number(analysis.fakeProbability) || 50;

    // Step 4: Update certificate record with all data
    await Certificates.update({
      id: cert.id,
      record: {
        status: 'Completed',
        result: validResult as any,
        confidenceScore: analysis.confidenceScore,
        reasons: analysis.reasons,
        analysisDetails: analysis.analysisDetails,
        originalProbability: origProb,
        fakeProbability: fakeProb,
        suspiciousRegions: typeof analysis.suspiciousRegions === 'string' ? analysis.suspiciousRegions : JSON.stringify(analysis.suspiciousRegions),
        extractedName: analysis.extractedName || '',
        extractedInstitution: analysis.extractedInstitution || '',
        extractedDate: analysis.extractedDate || '',
        extractedCertificateId: analysis.extractedCertificateId || '',
        extractedText: analysis.extractedText || '',
        isDuplicate,
        duplicateOf,
      },
    });

    const currentScans = context.user.totalScans || 0;
    await Users.update({ id: context.user.id, record: { totalScans: currentScans + 1 } });

    await AuditLogs.create({
      record: {
        user: context.user.id,
        action: isDuplicate ? 'Duplicate Certificate Detected' : 'Certificate Analyzed',
        details: `Analyzed "${input.fileName}" — Result: ${validResult} (${analysis.confidenceScore}%) | Original: ${origProb}% Fake: ${fakeProb}%`,
      },
    });

    return {
      certificateId: cert.id,
      result: validResult,
      confidenceScore: analysis.confidenceScore,
      originalProbability: origProb,
      fakeProbability: fakeProb,
      reasons: analysis.reasons,
      analysisDetails: analysis.analysisDetails,
      suspiciousRegions: typeof analysis.suspiciousRegions === 'string' ? analysis.suspiciousRegions : JSON.stringify(analysis.suspiciousRegions),
      extractedName: analysis.extractedName || '',
      extractedInstitution: analysis.extractedInstitution || '',
      extractedDate: analysis.extractedDate || '',
      extractedCertificateId: analysis.extractedCertificateId || '',
      extractedText: analysis.extractedText || '',
      isDuplicate,
      duplicateOf,
      qrCodeFound: !!analysis.qrCodeFound,
      digitalSignatureFound: !!analysis.digitalSignatureFound,
      tamperingIndicators: analysis.tamperingIndicators || 'None detected',
    };
  },
});

import { Card, CardContent } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Progress } from '@/components/ui/progress';
import { ShieldCheck, ShieldAlert, ShieldQuestion, QrCode, PenTool, ScanSearch, FileText, Copy, Download, Loader2, AlertTriangle } from 'lucide-react';
import { useState } from 'react';
import { generateReport } from 'zite-endpoints-sdk';
import { toast } from 'sonner';

type Props = {
  result: {
    certificateId: string;
    result: string;
    confidenceScore: number;
    originalProbability: number;
    fakeProbability: number;
    reasons: string;
    analysisDetails: string;
    suspiciousRegions: string;
    extractedName: string;
    extractedInstitution: string;
    extractedDate: string;
    extractedCertificateId: string;
    extractedText?: string;
    isDuplicate: boolean;
    duplicateOf?: string;
    qrCodeFound?: boolean;
    digitalSignatureFound?: boolean;
    tamperingIndicators?: string;
  };
  preview?: string | null;
  fileName?: string;
};

function ProbabilityBar({ label, value, color }: { label: string; value: number; color: string }) {
  return (
    <div className="space-y-1">
      <div className="flex justify-between text-sm">
        <span className="text-muted-foreground">{label}</span>
        <span className={`font-bold ${color}`}>{value.toFixed(1)}%</span>
      </div>
      <div className="h-3 rounded-full bg-muted overflow-hidden">
        <div className={`h-full rounded-full transition-all duration-1000 ${color === 'text-primary' ? 'bg-primary' : 'bg-destructive'}`} style={{ width: `${value}%` }} />
      </div>
    </div>
  );
}

function InfoPill({ icon: Icon, label, found }: { icon: any; label: string; found: boolean }) {
  return (
    <div className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-xs font-medium ${found ? 'bg-primary/15 text-primary' : 'bg-muted text-muted-foreground'}`}>
      <Icon className="h-3.5 w-3.5" />
      {label}: {found ? 'Detected' : 'Not Found'}
    </div>
  );
}

export default function ResultCard({ result, preview, fileName }: Props) {
  const [downloading, setDownloading] = useState(false);
  const isOriginal = result.result === 'Original';
  const isFake = result.result === 'Fake';

  const Icon = isOriginal ? ShieldCheck : isFake ? ShieldAlert : ShieldQuestion;
  const color = isOriginal ? 'text-primary' : isFake ? 'text-destructive' : 'text-yellow-500';
  const bgColor = isOriginal ? 'bg-primary/10' : isFake ? 'bg-destructive/10' : 'bg-yellow-500/10';

  let suspiciousRegions: string[] = [];
  try {
    const parsed = JSON.parse(result.suspiciousRegions || '[]');
    if (Array.isArray(parsed)) suspiciousRegions = parsed;
  } catch {
    if (result.suspiciousRegions) suspiciousRegions = [result.suspiciousRegions];
  }

  const handleDownloadReport = async () => {
    setDownloading(true);
    try {
      const { url } = await generateReport({ certificateId: result.certificateId });
      window.open(url, '_blank');
      toast.success('Report generated!');
    } catch {
      toast.error('Failed to generate report');
    } finally {
      setDownloading(false);
    }
  };

  return (
    <div className="space-y-4">
      {/* Duplicate Warning */}
      {result.isDuplicate && (
        <Card className="border-yellow-500/50 bg-yellow-500/10">
          <CardContent className="py-3 flex items-center gap-3">
            <Copy className="h-5 w-5 text-yellow-500" />
            <div>
              <p className="text-sm font-medium text-yellow-500">Duplicate Certificate Detected</p>
              <p className="text-xs text-muted-foreground">This certificate has been uploaded and analyzed before.</p>
            </div>
          </CardContent>
        </Card>
      )}

      {/* Main Result */}
      <Card className="overflow-hidden">
        <div className={`${bgColor} px-6 py-8 text-center`}>
          <Icon className={`h-16 w-16 mx-auto mb-3 ${color}`} />
          <Badge variant={isOriginal ? 'default' : isFake ? 'destructive' : 'secondary'} className="text-base px-4 py-1 mb-3">
            {result.result} Certificate
          </Badge>
          <div className="mt-2">
            <span className="text-4xl font-bold">{result.confidenceScore}%</span>
            <p className="text-sm text-muted-foreground mt-1">Confidence Score</p>
          </div>
        </div>

        <CardContent className="p-6 space-y-6">
          {/* Fraud Probability */}
          <div>
            <p className="text-sm font-semibold mb-3">Fraud Probability Assessment</p>
            <div className="space-y-3">
              <ProbabilityBar label="Original" value={result.originalProbability} color="text-primary" />
              <ProbabilityBar label="Fake" value={result.fakeProbability} color="text-destructive" />
            </div>
          </div>

          {/* Detection Pills */}
          <div className="flex flex-wrap gap-2">
            <InfoPill icon={QrCode} label="QR Code" found={!!result.qrCodeFound} />
            <InfoPill icon={PenTool} label="Digital Signature" found={!!result.digitalSignatureFound} />
          </div>

          {/* OCR Extracted Data */}
          {(result.extractedName || result.extractedInstitution || result.extractedDate || result.extractedCertificateId) && (
            <div>
              <p className="text-sm font-semibold mb-3 flex items-center gap-2"><FileText className="h-4 w-4 text-primary" /> OCR Extracted Data</p>
              <div className="grid grid-cols-2 gap-3 bg-muted/50 rounded-lg p-4">
                {result.extractedName && <ExtractedField label="Holder Name" value={result.extractedName} />}
                {result.extractedInstitution && <ExtractedField label="Institution" value={result.extractedInstitution} />}
                {result.extractedDate && <ExtractedField label="Date Issued" value={result.extractedDate} />}
                {result.extractedCertificateId && <ExtractedField label="Certificate ID" value={result.extractedCertificateId} />}
              </div>
            </div>
          )}

          {preview && (
            <div>
              <p className="text-sm font-semibold mb-2">Uploaded Certificate</p>
              <img src={preview} alt={fileName} className="rounded-lg border max-h-48 mx-auto" />
            </div>
          )}

          {/* Key Findings */}
          <div>
            <p className="text-sm font-semibold mb-2">Key Findings</p>
            <div className="text-sm text-muted-foreground whitespace-pre-line bg-muted/50 rounded-lg p-4">{result.reasons}</div>
          </div>

          {/* Suspicious Regions */}
          {suspiciousRegions.length > 0 && (
            <div>
              <p className="text-sm font-semibold mb-2 flex items-center gap-2">
                <ScanSearch className="h-4 w-4 text-destructive" /> Suspicious Regions Identified
              </p>
              <div className="space-y-2">
                {suspiciousRegions.map((region, i) => (
                  <div key={i} className="flex items-start gap-2 text-sm bg-destructive/5 border border-destructive/20 rounded-lg px-3 py-2">
                    <AlertTriangle className="h-4 w-4 text-destructive shrink-0 mt-0.5" />
                    <span>{region}</span>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Tampering Indicators */}
          {result.tamperingIndicators && result.tamperingIndicators !== 'None detected' && (
            <div>
              <p className="text-sm font-semibold mb-2">Tampering Indicators</p>
              <div className="text-sm text-muted-foreground whitespace-pre-line bg-destructive/5 border border-destructive/20 rounded-lg p-4">{result.tamperingIndicators}</div>
            </div>
          )}

          {/* Detailed Analysis */}
          <div>
            <p className="text-sm font-semibold mb-2">Detailed Analysis</p>
            <div className="text-sm text-muted-foreground bg-muted/50 rounded-lg p-4">{result.analysisDetails}</div>
          </div>

          {/* Download Report */}
          <Button onClick={handleDownloadReport} disabled={downloading} className="w-full gap-2" variant="outline">
            {downloading ? <Loader2 className="h-4 w-4 animate-spin" /> : <Download className="h-4 w-4" />}
            {downloading ? 'Generating Report…' : 'Download Verification Report (PDF)'}
          </Button>
        </CardContent>
      </Card>
    </div>
  );
}

function ExtractedField({ label, value }: { label: string; value: string }) {
  return (
    <div>
      <p className="text-xs text-muted-foreground uppercase tracking-wide">{label}</p>
      <p className="text-sm font-medium mt-0.5">{value}</p>
    </div>
  );
}

