  "originalProbability": <number 0-100>,
  "fakeProbability": <number 0-100>,
  "reasons": "<bullet list with \u2022 prefix for each key finding>",
  "analysisDetails": "<detailed multi-paragraph analysis covering all 10 dimensions>",
  "suspiciousRegions": "<JSON array of strings describing each suspicious area, e.g. [\\"Logo area: low resolution\\", \\"Name field: font mismatch\\"]>",
